"""
MKT Context Commentary — Genesis chapter 24
Run: python3 scripts/zc-context-genesis-24-24.py

Source data used:
- data/interlinear/genesis.json
- data/translation/draft/mediating/genesis.json (MKT text)
- data/commentary/mkt-context/genesis.json (prior chapters; merge_comm skips already-present entries)

Key decisions in this range:
- Ch24 is the longest chapter in Genesis (67 vv.) and the most fully developed narrative type-scene;
  it establishes the "woman at the well" pattern that recurs in Gen 29 (Jacob/Rachel) and Exod 2 (Moses/Zipporah)
- v2 "hand under thigh" oath: the thigh/loin (yarekh) is the seat of procreative power;
  swearing by it invokes the ancestors and descendants as witnesses
- v10 Aram Naharaim: "Aram of the Two Rivers" = the upper Mesopotamia / Paddan-Aram region (Harran);
  this is where Terah's household settled on the way from Ur (Gen 11:31)
- v12 and throughout: ḥeseḏ appears four times in this chapter — a theological keyword marking
  covenantal loyalty; translated "kindness" in the MKT but carries obligation, not mere sentiment
- v22 beka/ten shekels: these are precise ANE weights used in pre-coinage commerce; the gifts
  are given before Rebekah's lineage is confirmed — a storytelling risk that the narrative then resolves
- v55 "ten days": paralleled in Nuzi marriage contracts (14th c. BCE) as a waiting period before departure
- v60 blessing: virtually identical to Gen 22:17 — Rebekah's family unknowingly echoes the Aqedah blessing
- v63 lasuach (לָשׂוּחַ): hapax legomenon; translated variously as "meditate," "walk about," "pray"
- v65 the veil: in the ANE, a woman covering herself with a veil signaled the transition to
  betrothed/married status — not modesty alone, but a visible status marker
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

GENESIS = {
  "24": {
    "1": '<p>"Abraham was now very old, and the LORD had blessed him in every way" — the formula echoes the toledot structure: <em>bā bayyāmîm</em> (well advanced in age) is the same phrase used of both Abraham and Sarah in 18:11. The statement that YHWH "blessed him in every way" (<em>bakkōl</em>) is a summary before the chapter\'s main concern: what happens to that blessing after Abraham? The chapter\'s entire plot turns on securing a covenant heir\'s wife, and thus the continuity of the blessing itself.</p>',

    "2": '<p>"Put your hand under my thigh" — the oath gesture involves placing the hand near the generative organ (<em>yarekh</em>, thigh/loin; cf. the same word in the euphemism "those who came from his loins," Gen 46:26). The oath thereby invokes the power of procreation and the chain of descendants as witnesses; to break the oath would be to violate one\'s own posterity. This is the most solemn form of oath in the patriarchal narratives — it appears again in 47:29, when Jacob administers the same oath to Joseph. The servant is identified as the senior household manager (<em>zāqēn bêtô</em>, elder of his house), the person with the most authority and responsibility after Abraham himself.</p>',

    "3": '<p>"Swear by the LORD, the God of heaven and the God of earth" — the double title "God of heaven and God of earth" is unusual in Genesis (God of heaven alone is the more common form in later texts). The expanded form emphasizes YHWH\'s comprehensive sovereignty over both cosmic domains — relevant for an oath about a journey to a distant land. The prohibition against Canaanite wives reflects covenant endogamy: the covenant lineage must not be absorbed into Canaan\'s peoples, whose land YHWH has promised to Abraham\'s descendants. The same concern governs the Patriarchal period generally (cf. 26:34–35; 27:46) and surfaces later in Ezra\'s reforms.</p>',

    "4": '<p>"Go to my country and my own relatives" — Abraham\'s homeland is Aram Naharaim, the upper Mesopotamian region around Harran where Terah\'s extended family remained (Gen 11:31–32). The phrase <em>ʾel-ʾarṣî wĕʾel-môlaḏtî</em> (my land and my kindred) uses the same words Abraham heard reversed in the divine call of 12:1 (<em>lekh-lĕkhā mēʾarṣĕkhā ûmimmôlaḏtĕkhā</em> — "go from your land and your kindred"). The servant is being sent back to exactly what Abraham was called out of — but only to secure a bride, not to return and settle.</p>',

    "5": '<p>"What if the woman is unwilling to come back with me?" — the servant asks a legally precise question about the oath\'s conditions. In ANE marriage negotiations, a bride\'s willingness was a real factor, though the primary consent rested with her father and brother. The servant\'s concern reflects actual practice: a bride who refused to leave her family could not be compelled without creating a serious social breach. The question also establishes the oath\'s conditional clause — which Abraham answers in vv. 6–8 with equal precision, releasing the servant from obligation if the woman refuses.</p>',

    "6": '<p>"Make sure that you do not take my son back there" — Abraham\'s prohibition is absolute: under no circumstance is Isaac to leave Canaan and return to Mesopotamia. The land of promise must not be abandoned. This distinguishes Isaac from Abraham, who had temporarily sojourned in Egypt (Gen 12) — Isaac is later explicitly told not to go to Egypt (26:2). The covenant heir\'s presence in the land is itself a theological commitment.</p>',

    "7": '<p>"The LORD... will send his angel before you" — divine intermediaries (<em>malʾākîm</em>, messengers/angels) function as divine emissaries in ANE thought generally, but in Genesis YHWH\'s angel operates with particular directness, sometimes indistinguishable from YHWH himself (cf. 16:7–13; 22:11–12). Abraham\'s confidence that his angel will accompany the servant is grounded in the oath YHWH swore at Moriah (22:16–18) — a Davidic-style royal grant that Abraham now applies to the immediate practical mission. "To your offspring I will give this land" (12:7) is the covenant basis for insisting the right wife must be found.</p>',

    "8": '<p>"If the woman is unwilling to come back with you, then you will be released from this oath" — the release clause is legally precise: <em>wĕniqquîtā miššĕbuʿātî zōʾt</em> (you will be free/innocent from this my oath). The verb <em>nāqāh</em> is used in legal contexts for being acquitted or released from an obligation. The one absolute condition remains: Isaac must not be taken back to Mesopotamia. This careful legal framing reflects the seriousness of oaths in ANE culture — an oath sworn by the reproductive seat of one\'s ancestors could not be taken lightly.</p>',

    "9": '<p>"The servant put his hand under the thigh of his master Abraham and swore an oath to him concerning this matter" — the completion of the formal oath ceremony. The narrator uses the same vocabulary as v.2 to close the frame: the gesture and the swearing are both confirmed. Only after this legal formality does the narrative move to the journey. The ANE legal context is evident: oral oaths were binding contracts, and the specific gesture functioned as the equivalent of a signature or seal.</p>',

    "10": '<p>"Ten of his master\'s camels" — camels were luxury transportation in the early second millennium; they were expensive to maintain and functioned as a visible signal of wealth. "All kinds of good things from his master" likely refers to bride gifts (<em>mohar</em>, bride price) and hospitality provisions. <em>Aram Naharaim</em> (ʾărām naharāyim) means "Aram of the Two Rivers" — the region between the Euphrates and the Balikh or Khabur rivers, centering on Harran in modern southeastern Turkey. "The town of Nahor" (ʿîr Nāḥôr) may refer to Harran itself or to Nahor\'s settlement nearby; ancient texts from Mari and Nuzi mention a city "Nakhur" in this region.</p>',

    "11": '<p>"The time the women come out to draw water" — the evening was the standard hour for water collection throughout the ancient Near East; the heat of the day had passed, and the communal well was a primary social gathering point. The scene establishes the location (outside the town, near the well) and the social custom (women as water-bearers). In the ANE, public wells were both practical infrastructure and social spaces where community life intersected. The servant\'s positioning here is strategic: he will observe the young women of the community in a natural, socially appropriate setting.</p>',

    "12": '<p>"LORD, God of my master Abraham, make me successful today" — this is one of the few recorded prayers by a non-patriarch in Genesis; it establishes the servant as a model of covenant dependence. <em>Haqreh-nāʾ</em> (please make it happen, grant me success) uses the verb <em>qārāh</em>, often used for divinely appointed encounters (cf. Ruth 2:3, where Ruth "happened upon" Boaz\'s field). The servant does not presume; he prays. "Show kindness (<em>ḥeseḏ</em>) to my master Abraham" — the first of four occurrences of <em>ḥeseḏ</em> in this chapter. The term carries covenantal freight: it is the loyalty owed within a covenant relationship, not mere sentiment.</p>',

    "13": '<p>"See, I am standing beside this spring, and the daughters of the townspeople are coming out to draw water" — the servant\'s prayer incorporates the actual situation: the spring, the women arriving. This is not a generic petition but a situationally specific one, which makes the immediate answer (v.15) all the more striking. The public well as marriage-meeting venue is a repeated type-scene in the OT (Gen 29:1–12; Exod 2:15–21) — the "woman at the well" pattern signals a pivotal moment in the narrative.</p>',

    "14": '<p>"May it be that when I say... \'Drink, and I\'ll water your camels too\'" — the servant\'s requested sign is carefully designed. Offering to water a stranger\'s camels was far beyond ordinary hospitality: ten camels can drink 20–30 gallons each after a long journey, meaning Rebekah would need to draw and carry hundreds of gallons of water. The sign tests not just hospitality but extraordinary generosity and initiative — precisely the character trait suited to become a patriarch\'s wife. "By this I will know that you have shown kindness (<em>ḥeseḏ</em>) to my master" — the sign, if given, will be the demonstration of divine covenant-loyalty.</p>',

    "15": '<p>"Before he had finished praying, Rebekah came out" — the narrative signals divine immediacy: the answer arrives before the prayer is complete. Rebekah is introduced with a full genealogy: daughter of Bethuel son of Milcah, wife of Nahor (Abraham\'s brother). This lineage is crucial — she is from the right family, the one to which the oath directs the servant. The detail "her jar on her shoulder" is realistic: women carried water jars on the shoulder or head in the ANE, and Rebekah\'s carrying position confirms she is here for the purpose the servant\'s sign requires.</p>',

    "16": '<p>"The woman was very beautiful, a virgin; no man had ever slept with her" — the narrator provides both an aesthetic and a legal status assessment. <em>Beṯûlāh</em> (virgin) was a specific legal category relevant to marriage negotiations under ANE law: the bride\'s virgin status was a condition of the full bride price (<em>mohar</em>) and was protected by legal codes (cf. Exod 22:16–17; Deut 22:28–29). The redundant clarification ("no man had ever slept with her") is not literary excess but legal precision — the narrator confirms both the social category and the biological fact, because both matter for the betrothal to follow.</p>',

    "17": '<p>"The servant hurried to meet her and said, \'Please give me a little water from your jar\'" — <em>wayyārāṣ</em> (he ran to meet her) signals the servant\'s intentionality; this is not a casual encounter. His request is modest: "a little water" (<em>gāmĕʿîm-nāʾ mĕʿaṭ-mayim</em>) — a minimal ask that makes Rebekah\'s subsequent offer of camel-watering all the more generous. The social dynamics are careful: a man asking a woman for water was not improper in this context, as the public well was a community space.</p>',

    "18": '<p>"Drink, my lord" — Rebekah addresses the stranger with the honorific <em>ʾăḏōnî</em> (my lord), which signals both respect for a guest and her own social awareness. She "quickly lowered the jar to her hands" — the phrase emphasizes speed and willingness. The immediate, generous response to a stranger\'s request for water is characteristic of the patriarchal virtue of hospitality (<em>ḥăkamat-libbāh</em>, not specifically stated here but implied). The generosity of Rebekah\'s response will be confirmed and exceeded in v.19.</p>',

    "19": '<p>"I\'ll draw water for your camels too, until they have had enough to drink" — Rebekah\'s initiative goes far beyond what the sign required. She does not merely offer; she commits to seeing it through — "until they have had enough" (<em>ʿad ʾim-killû lišetōt</em>, until they have finished drinking). This is not a token gesture. Ten camels returning from a long journey could drink upward of 200–300 gallons total. The offer demonstrates exactly the quality the servant prayed for: extraordinary, self-initiating covenant-loyalty (<em>ḥeseḏ</em>) enacted toward a stranger.</p>',

    "20": '<p>"She quickly emptied her jar into the trough, ran back to the well to draw more water, and drew enough for all his camels" — the narrative emphasizes physical exertion and repeated action: empty, run, draw, repeat. The word <em>wattĕmahēr</em> (she hurried/ran quickly) appears twice in this chapter for Rebekah (vv.18, 20), and <em>wattāroṣ</em> (she ran) marks her initiative. The trough (<em>šeqet</em>) was a stone watering basin beside wells where animals drank. Rebekah\'s labor is presented without complaint or hesitation — the narrative\'s verdict on her character before the servant\'s verdict is given.</p>',

    "21": '<p>"Without saying a word, the man watched her closely to learn whether or not the LORD had made his journey successful" — <em>mišṯāʾēh lāh</em> (gazing at her/watching her intently) reflects the servant\'s deliberate silence while the sign is being confirmed. He does not yet know if the camel-watering will materialize; he watches and waits. The phrase "whether or not the LORD had made his journey successful" (<em>hahiṣlîaḥ YHWH darkô ʾim-lōʾ</em>) maintains the theological frame: the outcome depends on YHWH\'s action, not the servant\'s skill. This moment of suspended observation is the narrative\'s dramatic center.</p>',

    "22": '<p>"A gold nose ring weighing a beka and two gold bracelets weighing ten shekels" — a <em>beqaʿ</em> (beka) was half a shekel, approximately 5.7 grams; the nose ring was therefore roughly 5.7g of gold. The two bracelets weighed ten shekels total (approximately 114g of gold) — a substantial sum. These are formal betrothal gifts, given before Rebekah\'s family connection to Abraham is confirmed. The narrative allows the reader to feel the tension: the servant is committing significant resources on the strength of a sign, without yet knowing her lineage. The gifts signal serious matrimonial intent; ANE betrothal practice included gifts to the bride and her family.</p>',

    "23": '<p>"Whose daughter are you? Please tell me, is there room in your father\'s house for us to spend the night?" — only now does the servant ask the crucial lineage question. The sequence (gifts first, lineage inquiry second) is either a narrative device for suspense, or reflects a cultural practice of establishing hospitality ties before identifying connections. The request for lodging (<em>bêt ʾābîkī</em>, your father\'s house) invokes the ANE hospitality code: the household unit (<em>bêt ʾāv</em>) was the basic social structure, and lodging requests were made through its head.</p>',

    "24": '<p>"I am the daughter of Bethuel, the son that Milcah bore to Nahor" — Rebekah\'s self-identification gives the full genealogical chain needed to confirm she is from Abraham\'s extended family. Bethuel is Abraham\'s nephew (son of his brother Nahor by Milcah); Rebekah is therefore Abraham\'s grandniece. The matrilineal specification ("the son that Milcah bore to Nahor") is important in the ANE context: lineage through a principal wife (as opposed to a concubine like Nahor\'s concubine Reumah, 22:24) confirmed the child\'s full social standing and inheritance rights.</p>',

    "25": '<p>"We have plenty of straw and fodder, as well as room for you to spend the night" — Rebekah\'s hospitality response uses the formal vocabulary of ANE guest-welcome: straw and fodder for animals, space for the travelers. Her answer demonstrates that the household is in a position to receive guests properly — this is not charity but the fulfillment of the social obligation of hospitality. In the ANE, refusing to offer hospitality to travelers was a serious social failure; Rebekah\'s immediate assurance removes any possible ambiguity.</p>',

    "26": '<p>"Then the man bowed down and worshiped the LORD" — the servant\'s immediate response to Rebekah\'s lineage revelation is liturgical. Before anything else, he bows (<em>wayyiqqōd</em>) and worships (<em>wayyištaḥû</em>) YHWH. The two verbs — prostration and worship — appear together in other moments of covenant encounter (Exod 4:31; 12:27). The servant does not first arrange the logistics of hospitality; he first acknowledges the divine action he has just witnessed. This behavioral model — recognizing providential alignment before proceeding — marks the servant as a man of genuine covenant piety.</p>',

    "27": '<p>"Who has not abandoned his kindness and faithfulness to my master" — <em>ḥeseḏ wĕʾemet</em> (covenant-loyalty and faithfulness) is a paired formula that appears throughout the OT as shorthand for YHWH\'s covenant character (Exod 34:6; Ps 25:10; 86:15). The two terms together express the twofold aspect of the covenant relationship: <em>ḥeseḏ</em> is the loving-loyalty owed within the covenant bond; <em>ʾemet</em> is the reliability and consistency that makes that loyalty trustworthy. The servant recognizes that what has just happened at the well is not coincidence but covenant faithfulness — YHWH has kept his word to Abraham.</p>',

    "28": '<p>"The young woman ran and told her mother\'s household" — Rebekah reports to her <em>bêt ʾimmāh</em> (her mother\'s household), not to her father\'s house. This is notable: in the ANE, the women\'s quarters were often functionally separate from the men\'s domain, and women\'s business (especially marriage negotiations in their early stages) might be handled within the mother\'s sphere first. The specification of the mother\'s household may also prepare for Laban\'s prominent role — Bethuel (the father) is largely absent from the negotiations, while Laban acts as household authority.</p>',

    "29": '<p>"Rebekah had a brother named Laban, and he hurried out to the man at the spring" — Laban\'s first appearance in Genesis. He will become a central figure in the Jacob cycle (Gen 29–31). The narrator introduces him here through his response to news of the stranger at the well. His haste is noted, and v.30 reveals its motivation: he had seen the gold jewelry. Laban\'s character as economically motivated is established from his first scene; compare his later willingness to work Jacob hard for his daughters\' hands.</p>',

    "30": '<p>"As soon as he had seen the nose ring, and the bracelets on his sister\'s arms" — the narrative gives the reader Laban\'s internal motivation before describing his outward behavior. The sequence (he saw the gold → he heard Rebekah\'s report → he went out) makes his economic interest the first cause of his hospitality. This is not necessarily venal in the ANE context — bride gifts signaled the visitor\'s wealth and serious matrimonial intent, which was relevant information for the family. But the narrator\'s sequencing quietly flags what drives Laban.</p>',

    "31": '<p>"Come, you who are blessed by the LORD" — Laban uses YHWH\'s name (<em>bārûkh YHWH</em>, blessed of YHWH) — remarkable from a Mesopotamian household. Abraham\'s family apparently maintained YHWH-awareness despite living in Aram (cf. 31:19, where Laban has household idols — <em>ṭĕrāpîm</em> — suggesting a mixed religious household). Laban\'s recognition of YHWH\'s blessing on the servant may be genuine or diplomatic; the narrator does not adjudicate. "I have prepared the house and a place for the camels" — the hospitality formula confirms the household is ready to receive guests properly.</p>',

    "32": '<p>"The camels were unloaded. Straw and fodder were brought for the camels, and water for him and his men to wash their feet" — the hospitality sequence follows standard ANE protocol: animals cared for, then guests\' feet washed (removing the dust and defilement of travel), then a meal prepared. Feet-washing as a gesture of hospitality appears throughout the OT and NT (Gen 18:4; 43:24; 1 Sam 25:41; John 13:1–17). The detail of camel care precedes human care — the animals\' needs were attended first, as they represented the host\'s obligation to the full party.</p>',

    "33": '<p>"I will not eat until I have told you what I have to say" — the servant\'s refusal to eat until his mission is explained reverses the normal ANE hospitality sequence: typically, guests were fed before business was conducted. The inversion signals the urgency of the divine commission — this is not an ordinary commercial or social visit. The refusal is not rudeness; it is a declaration that the servant\'s primary obligation (the oath, the mission, YHWH\'s direction) takes precedence over even the sacred social protocol of the guest meal.</p>',

    "34": '<p>"I am Abraham\'s servant" — the servant\'s opening self-identification is remarkably simple: no name, just his master\'s name. Throughout this chapter the servant is never named; he functions entirely in relation to Abraham. Some rabbinic tradition identifies him with Eliezer of Damascus (Gen 15:2), but the text does not make this identification. The anonymity may be deliberate — his personal identity is subsumed in his role as covenant emissary.</p>',

    "35": '<p>"The LORD has blessed my master abundantly" — the servant begins his case by establishing Abraham\'s covenant status and material wealth. The inventory — sheep, cattle, silver, gold, male and female servants, camels, donkeys — follows a standard ANE list of wealth categories found in administrative texts. This is not mere boasting; in ANE marriage negotiations, the groom\'s family was expected to demonstrate capacity to provide a bride price (<em>mohar</em>) and maintain the bride. The servant is establishing that Isaac is a man of appropriate social and economic standing.</p>',

    "36": '<p>"My master\'s wife Sarah has borne him a son in his old age, and he has given him everything he owns" — the inheritance transfer is directly relevant to the bride negotiation: the wife being sought is not for a son of uncertain inheritance but for the sole heir of everything Abraham possesses. Sarah\'s age at Isaac\'s birth (she was approximately 90, Gen 17:17) is implicitly recalled by "in his old age." The miraculous nature of Isaac\'s birth — which the audience knows — is the background for why this match is a covenant matter, not merely a family preference.</p>',

    "37": '<p>"My master made me take an oath" — the servant recounts the oath of vv. 2–4, now in direct speech as part of his negotiation speech. The recounting serves dual purposes: it explains the servant\'s mission and it makes Abraham\'s instructions directly audible to Laban and Bethuel. The prohibition against Canaanite wives would resonate with a Mesopotamian family — they are being told they are specifically preferred over the local alternatives, a form of implied honor.</p>',

    "38": '<p>"Go to my father\'s family and to my own clan, and get a wife for my son" — <em>mišpāḥāh</em> (clan, extended family group) is the social unit between the household (<em>bêt ʾāv</em>) and the tribe (<em>šēbeṭ</em>). The servant\'s version slightly expands the original: "my father\'s family" adds the patrilineal dimension to "my country and my own relatives" from v.4. The emphasis on family connection is the heart of endogamous marriage: the covenant line must remain within recognizable kinship.</p>',

    "39": '<p>"Then I asked my master, \'What if the woman will not come back with me?\'" — the servant recounts his own question from v.5 verbatim. The repetition is characteristic of this chapter, which replays the earlier events in the servant\'s own account with minor variations. The Near Eastern narrative style of extended repetition was not considered redundant; it was a form of emphasis and oral tradition — the repeated version confirms and validates the first.</p>',

    "40": '<p>"The LORD, before whom I have walked faithfully" — the phrase <em>ʾăšer-hithalakhti lĕpānāyw</em> (before whom I have walked) is the language of covenantal fidelity. The same idiom appears in 17:1, where YHWH commands Abraham to "walk before me" (<em>hithalekh lĕpānay</em>). Abraham\'s claim is that his covenant walk has been consistently faithful — a claim the narrative has substantially confirmed. The servant repeats Abraham\'s confidence (from v.7) that the angel of YHWH will accompany and succeed the mission.</p>',

    "41": '<p>"And if you go to my clan and they refuse to give her to you — you will be released from my oath" — the servant recounts the release clause of v.8. The legal precision is exact: refusal by the family (<em>wĕʾim-lōʾ yittĕnû lākh</em>, if they will not give her to you) releases the oath. This protects the servant from penalty if the mission fails through no fault of his own. The conditional structure of the oath mirrors ANE suzerain-vassal treaty language, where obligations were formally contingent on specific circumstances.</p>',

    "42": '<p>"When I came to the spring today, I said..." — the servant\'s recounting of his prayer at the spring compresses the narrative from vv. 12–14. His account before Laban is slightly different in emphasis from the narrator\'s account: here the servant highlights his own prayer and the sign he requested, making visible the theological frame — this was not an accidental meeting but a prayed-for encounter. The repetition allows Laban and Bethuel (and the reader) to understand that what happened was a divinely arranged sign, not mere coincidence.</p>',

    "43": '<p>"If a young woman comes out to draw water and I say to her, \'Please let me drink a little water from your jar\'" — the servant recounts his sign request, substituting <em>ʿalmāh</em> (young woman) for <em>naʿărāh</em> (girl/young woman) used in the narrator\'s account. <em>ʿAlmāh</em> can mean a young woman of marriageable age; the LXX translates it <em>parthenos</em> (virgin) when it appears in Isa 7:14. Here it simply means an unmarried young woman of the community — the same social category as the narrator\'s <em>naʿărāh</em> in v.16.</p>',

    "44": '<p>"Let her be the one the LORD has chosen for my master\'s son" — the servant\'s account of the sign condenses the original prayer (v.14) by replacing "for your servant Isaac" with "for my master\'s son," maintaining appropriate deference. The emphasis on YHWH having "chosen" (<em>hōkhîaḥ</em>, designated, appointed) is significant: the servant frames the marriage as a divine election, not a human selection. This framing makes refusal more difficult for Laban and Bethuel — they would be declining YHWH\'s own appointment.</p>',

    "45": '<p>"Before I finished praying in my heart" — the detail <em>bĕlibbî</em> (in my heart) appears here in the servant\'s account but not in the narrator\'s description of the prayer (vv. 12–14). This specifies that the prayer was interior — not spoken aloud. This is notable in the ANE context where prayers were typically voiced; silent prayer was less common and signals an intimacy of address to YHWH. The speed of the answer (before the prayer was finished) is also emphasized more clearly here than in the narrator\'s version.</p>',

    "46": '<p>"She quickly lowered her jar from her shoulder and said, \'Drink, and I\'ll water your camels too\'" — the servant\'s retelling of Rebekah\'s response (originally vv.18–19) highlights the double offer and the immediacy. He quotes her directly, giving Laban and Bethuel the impression of verbatim report — a sign that this account is truthful, not embellished. In ANE hospitality culture, an account that quotes others directly was a form of witness testimony.</p>',

    "47": '<p>"I put the ring in her nose and the bracelets on her arms" — the servant\'s account of the gifts (cf. v.22) notes that he placed the ring and bracelets on Rebekah before confirming her lineage, just as the narrator described. This sequence was potentially problematic: the gifts were given prematurely. The servant reports it honestly anyway. In ANE negotiation contexts, an honest account — even of a potentially embarrassing sequence — would have been more persuasive than a sanitized version.</p>',

    "48": '<p>"Who had led me on the right road to get the granddaughter of my master\'s brother for his son" — the servant\'s thanksgiving prayer (cf. vv. 26–27) now adds the specific kinship identification: Rebekah is Abraham\'s grandniece. The phrase "the right road" (<em>derek ʾemet</em>, the road of faithfulness/truth) echoes the <em>ḥeseḏ wĕʾemet</em> formula from v.27 — YHWH\'s guidance was not only providential but covenantally reliable.</p>',

    "49": '<p>"Now if you will show kindness and faithfulness to my master, tell me" — the servant uses the <em>ḥeseḏ wĕʾemet</em> formula now as a request directed at Laban and Bethuel. He invites them to participate in YHWH\'s covenant action by extending their own covenant-loyalty to Abraham. The choice of this specific vocabulary is deliberate: by using the same language he has applied to YHWH\'s action throughout the chapter, the servant implicitly frames the human decision as a response to divine initiative. "So I may know which way to turn" is literally "so I may turn right or left" — an idiom for knowing how to proceed.</p>',

    "50": '<p>"Laban and Bethuel answered, \'This is from the LORD; we can say nothing to you one way or the other\'" — the response is the most theologically striking line in the chapter. Two members of a Mesopotamian household, living far from Canaan, recognize YHWH\'s directing hand and explicitly acknowledge that they are not in a position to resist it. <em>Mēʾēt YHWH yāṣāʾ haddāḇār</em> (from YHWH this thing has gone out) — the phrasing is of divine decree. Whether their acknowledgment reflects genuine faith or pragmatic recognition of an irresistible force, the narrative presents it as the theological resolution of the chapter\'s central question.</p>',

    "51": '"Here is Rebekah; take her and go" — the formal transfer of Rebekah is expressed in language that echoes ANE betrothal formulas: presenting the bride and authorizing the departure. The phrase "as the LORD has directed" (<em>kaʾăšer dibbēr YHWH</em>) grounds the family\'s decision in the divine word — they are not conceding to the servant\'s persuasion but to YHWH\'s prior direction. This language positions the betrothal as covenantally legitimate.',

    "52": '<p>"When Abraham\'s servant heard what they said, he bowed down to the ground before the LORD" — worship is again the servant\'s first response to a pivotal confirmation (cf. v.26 when Rebekah\'s lineage was revealed). The pattern is consistent: recognition → worship → action. This is the servant\'s second prostration before YHWH in this chapter, marking the two hinge moments of the narrative: the confirmation of lineage and the family\'s consent.</p>',

    "53": '<p>"Gold and silver jewelry and articles of clothing and gave them to Rebekah; he also gave costly gifts to her brother and to her mother" — these are the formal betrothal gifts in two registers: gifts to the bride herself (personal jewelry and clothing) and gifts to the household (<em>mōhar</em> equivalents for the family). The distribution — to Rebekah, then to her brother and mother — follows the ANE pattern where the bride received a personal trousseau and the family received the bride price. Nuzi tablets and other ANE texts detail similar distributions of gifts at the time of betrothal.</p>',

    "54": '<p>"He and the men who were with him ate and drank and spent the night there" — only after the betrothal is formally completed does the servant accept hospitality, a delayed fulfillment of the earlier refusal (v.33). The eating and drinking now mark the covenant meal — in ANE practice, the shared meal often sealed a covenant or agreement. The morning brings his request to depart immediately, signaling that the mission\'s completion compels urgency.</p>',

    "55": '<p>"Let the young woman remain with us ten days or so; then you may go" — a waiting period before the bride\'s departure was standard in ANE marriage practice. Nuzi tablets (14th century BCE, from upper Mesopotamia, close to Aram Naharaim culturally) document that a bride would remain in her father\'s house for a specified period after betrothal before departing to her husband. Ten days (<em>yāmîm ʾô ʿāśôr</em>, days or ten) is a round number rather than a precise legal term — the family is seeking minimal time to prepare Rebekah and say farewell.</p>',

    "56": '<p>"Do not detain me, now that the LORD has granted success to my journey" — the servant\'s urgency is grounded in the divine commissioning: the mission is complete, and delay is resistance to YHWH\'s work. <em>ʾAl-tĕʾaḥărû ʾōtî</em> (do not delay me) — the verb <em>ʾāḥar</em> appears in contexts where divine momentum should not be impeded (cf. Josh 10:13, where the sun does not hasten). The servant\'s refusal of the delay is not rudeness but theological urgency.</p>',

    "57": '<p>"Let\'s call the young woman and ask her about it" — the family\'s decision to consult Rebekah directly is notable. In many ANE legal contexts, a woman\'s consent to marriage was not formally required; her father\'s word was sufficient. Here, the family takes an extra step — possibly because the unusual circumstances (an immediate departure, a long journey, a groom she has never met) warranted her explicit consent. Alternatively, this may reflect that Rebekah\'s own willingness is the final piece of the divine sign — YHWH\'s direction has been confirmed at every level.</p>',

    "58": '<p>"Will you go with this man?" "I will go" — Rebekah\'s answer is one of the most decisive in the OT: <em>ʾēlēkh</em>, simply "I will go." It mirrors Abraham\'s own departure in 12:4 (<em>wayyēlekh</em>, and he went) — a single-word obedience to a life-altering call. Her willingness is given without hesitation or conditions. The question put to her echoes the divine call structure: are you willing to leave your household and go? Her affirmative answer is her own covenant step, parallel to Abraham\'s.</p>',

    "59": '<p>"They sent their sister Rebekah on her way, along with her nurse" — Rebekah\'s nurse is identified as traveling with her; in 35:8, she is named Deborah, and her death is mourned. Household nurses (<em>mêneqet</em>, from the verb "to nurse/suckle") were significant figures in the ancient household; Rebekah\'s nurse traveled with her to Canaan and remained with the household for the rest of her life. The inclusion of the nurse signals that Rebekah is not departing alone and stripped of all connection — a significant caregiver goes with her.</p>',

    "60": '<p>"May you increase to thousands upon thousands; may your offspring possess the cities of their enemies" — the blessing given at departure is a formal send-off pronouncement. Its language is almost verbatim from 22:17, the Aqedah blessing on Abraham after the near-sacrifice of Isaac: "your offspring will take possession of the cities of their enemies." Rebekah\'s family unknowingly echoes the covenant promise — their blessing aligns exactly with the Abrahamic covenant without their being aware of it. This convergence of blessing language is the narrative\'s signal that everything is aligned: YHWH, Abraham, the servant, and now Rebekah\'s own family all point in the same direction.</p>',

    "61": '<p>"Rebekah and her attendants got ready and mounted the camels and went back with the man. So the servant took Rebekah and left" — the departure is narrated efficiently. Rebekah is now formally in the servant\'s custody; the marital transfer is underway. The use of <em>wayyiqqaḥ</em> (he took, lit. "he received/took") echoes the betrothal vocabulary — the same verb appears in marriage contexts throughout the OT (e.g., 24:3, 4; 25:1; 26:34).</p>',

    "62": '<p>"Now Isaac had come from Beer Lahai Roi, for he was living in the Negev" — Beer Lahai Roi is the well where Hagar encountered the angel of YHWH (Gen 16:14, "the well of the Living One who sees me"). Isaac\'s presence there connects him quietly to the Hagar narrative — the place where divine sight and mercy were made visible is now where the covenant heir lives. The Negev (the southern desert region) is where Isaac will spend his life (26:22), in contrast to Abraham\'s broader movements. Beer Lahai Roi becomes Isaac\'s spiritual landmark.</p>',

    "63": '<p>"He went out to the field one evening to meditate" — <em>lāśûaḥ baśśādeh</em> (to meditate/walk about in the field) uses <em>śûaḥ</em>, a hapax legomenon. The ancient versions differ: LXX has <em>adoleschēsai</em> (to converse, to meditate); Vulgate has <em>meditari</em> (to meditate); Targum Onkelos has "to pray." The evening hour is the traditional time of prayer in Jewish practice (cf. Ps 55:17; Dan 6:10). Isaac in the field at dusk — solitary, in the open, at the hour of prayer — is presented as a man of devotional habit. His posture contrasts with the active narrative energy of the chapter to this point.</p>',

    "64": '<p>"Rebekah also looked up and saw Isaac. She got down from her camel" — the mutual seeing (<em>wattisśāʾ Riḇqāh ʾet-ʿênêhā wattēreʾ ʾet-Yiṣḥāq</em>) recalls Isaac\'s name: <em>yiṣḥāq</em>, he laughs/he will laugh. Rebekah\'s act of dismounting from the camel (<em>wattippoḷ mēʿal haggāmāl</em>) is a gesture of deference: one does not remain mounted when encountering a social superior. The verb <em>nāpal</em> (fall/alight) suggests a swift, deliberate descent, not a stumble.</p>',

    "65": '<p>"So she took her veil and covered herself" — the veil (<em>ṣāʿîp</em>) in the ANE was a status marker for a betrothed or married woman, distinguishing her from an unmarried girl. The act of veiling at the sight of her husband-to-be signaled that she was now formally in the process of transfer from her family of origin to her husband\'s household. The same garment appears in 38:14 and 19, where Tamar uses a veil to adopt the appearance of a prostitute — the contrast underscores that the veil\'s significance was conventional and context-dependent, not inherent.</p>',

    "66": '<p>"Then the servant told Isaac all he had done" — the servant\'s report to Isaac is the formal completion of the commission: he was sent to find a wife, he found her, and now he gives account to his master\'s heir. The report is not narrated in detail — the reader has heard it twice already (narrator\'s account, servant\'s account to Laban). The third telling is passed over in silence, signaling that its content is known and its function is simply the formal close of the mission.</p>',

    "67": '<p>"Isaac brought her into the tent of his mother Sarah, and he married Rebekah" — the tent of Sarah is the matriarchal center of the household; its mention connects Isaac\'s new marriage to the covenant matriarch who has just died (Gen 23). Rebekah enters the household through the space defined by her predecessor. "He loved her" (<em>wayeʾehāḇehā</em>) — one of the few explicit statements of marital love in the OT. Isaac is comforted after his mother\'s death: the covenant\'s next generation is secured, grief is metabolized through love, and the Abrahamic line continues.</p>',
  }
}

def main():
    existing = load_comm('mkt-context', 'genesis')
    merge_comm(existing, GENESIS)
    save_comm('mkt-context', 'genesis', existing)
    print('Genesis 24 mkt-context written.')

if __name__ == '__main__':
    main()
